class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    parent_id = graphene.ID()
    parent = graphene.Field(lambda: Category)
    subcategories = graphene.List(lambda: Category)
    products = graphene.List(lambda: Product)

    def resolve_parent(self, info):
        if self.parent_id:
            return next((cat for cat in categories_data if cat['id'] == self.parent_id), None)
        return None

    def resolve_subcategories(self, info):
        return [cat for cat in categories_data if cat.get('parent_id') == self.id]

    def resolve_products(self, info):
        return [prod for prod in products_data if prod['category_id'] == self.id]


class Review(graphene.ObjectType):
    id = graphene.ID()
