class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category_id = graphene.ID()
    stock = graphene.Int()
    created_at = graphene.String()
    category = graphene.Field(Category)
    reviews = graphene.List(Review)
    average_rating = graphene.Float()
    review_count = graphene.Int()

    def resolve_category(self, info):
        return next((cat for cat in categories_data if cat['id'] == self.category_id), None)

    def resolve_reviews(self, info):
        return [rev for rev in reviews_data if rev['product_id'] == self.id]

    def resolve_average_rating(self, info):
        product_reviews = [rev for rev in reviews_data if rev['product_id'] == self.id]
        if not product_reviews:
            return 0.0
        return sum(rev['rating'] for rev in product_reviews) / len(product_reviews)

    def resolve_review_count(self, info):
        return len([rev for rev in reviews_data if rev['product_id'] == self.id])


class Query(graphene.ObjectType):
    products = graphene.List(
        Product,
        category_id=graphene.ID(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        search=graphene.String()
    )
    product = graphene.Field(Product, id=graphene.ID(required=True))
    
    categories = graphene.List(Category, parent_id=graphene.ID())
    category = graphene.Field(Category, id=graphene.ID(required=True))
    
    reviews = graphene.List(
        Review,
        product_id=graphene.ID(),
        min_rating=graphene.Int(),
        max_rating=graphene.Int()
    )
    review = graphene.Field(Review, id=graphene.ID(required=True))
    
    product_reviews = graphene.List(Review, product_id=graphene.ID(required=True))

    def resolve_products(self, info, category_id=None, min_price=None, max_price=None, search=None):
        result = products_data.copy()
        
        if category_id:
            result = [p for p in result if p['category_id'] == category_id]
        
        if min_price is not None:
            result = [p for p in result if p['price'] >= min_price]
        
        if max_price is not None:
            result = [p for p in result if p['price'] <= max_price]
        
        if search:
            search_lower = search.lower()
            result = [p for p in result if search_lower in p['name'].lower() or search_lower in p['description'].lower()]
        
        return result

    def resolve_product(self, info, id):
        return next((prod for prod in products_data if prod['id'] == id), None)

    def resolve_categories(self, info, parent_id=None):
        if parent_id is None:
            return [cat for cat in categories_data if cat.get('parent_id') is None]
        return [cat for cat in categories_data if cat.get('parent_id') == parent_id]

    def resolve_category(self, info, id):
        return next((cat for cat in categories_data if cat['id'] == id), None)

    def resolve_reviews(self, info, product_id=None, min_rating=None, max_rating=None):
        result = reviews_data.copy()
        
        if product_id:
            result = [r for r in result if r['product_id'] == product_id]
        
        if min_rating is not None:
            result = [r for r in result if r['rating'] >= min_rating]
        
        if max_rating is not None:
            result = [r for r in result if r['rating'] <= max_rating]
        
        return result

    def resolve_review(self, info, id):
        return next((rev for rev in reviews_data if rev['id'] == id), None)

    def resolve_product_reviews(self, info, product_id):
        return [rev for rev in reviews_data if rev['product_id'] == product_id]


class CreateReview(graphene.Mutation):
    class Arguments:
        product_id = graphene.ID(required=True)
        user_name = graphene.String(required=True)
        rating = graphene.Int(required=True)
        title = graphene.String(required=True)
        comment = graphene.String()

    review = graphene.Field(Review)
    success = graphene.Boolean()

    def mutate(self, info, product_id, user_name, rating, title, comment=None):
        product = next((p for p in products_data if p['id'] == product_id), None)
        if not product:
            return CreateReview(review=None, success=False)
        
        if rating < 1 or rating > 5:
            return CreateReview(review=None, success=False)
        
        new_review = {
            'id': str(len(reviews_data) + 1),
            'product_id': product_id,
            'user_name': user_name,
            'rating': rating,
            'title': title,
            'comment': comment or '',
            'created_at': datetime.utcnow().isoformat()
        }
        reviews_data.append(new_review)
        
        return CreateReview(review=new_review, success=True)


class CreateProduct(graphene.Mutation):
    class Arguments:
        name = graphene.String(required=True)
        description = graphene.String(required=True)
        price = graphene.Float(required=True)
        category_id = graphene.ID(required=True)
        stock = graphene.Int(required=True)

    product = graphene.Field(Product)
    success = graphene.Boolean()

    def mutate(self, info, name, description, price, category_id, stock):
        category = next((c for c in categories_data if c['id'] == category_id), None)
        if not category:
            return CreateProduct(product=None, success=False)
        
        new_product = {
            'id': str(len(products_data) + 1),
            'name': name,
            'description': description,
            'price': price,
            'category_id': category_id,
            'stock': stock,
            'created_at': datetime.utcnow().isoformat()
        }
        products_data.append(new_product)
        
        return CreateProduct(product=new_product, success=True)


class UpdateProduct(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)
        name = graphene.String()
        description = graphene.String()
        price = graphene.Float()
        stock = graphene.Int()

    product = graphene.Field(Product)
    success = graphene.Boolean()

    def mutate(self, info, id, name=None, description=None, price=None, stock=None):
        product = next((p for p in products_data if p['id'] == id), None)
        if not product:
            return UpdateProduct(product=None, success=False)
        
        if name:
            product['name'] = name
        if description:
            product['description'] = description
        if price is not None:
            product['price'] = price
        if stock is not None:
            product['stock'] = stock
        
        return UpdateProduct(product=product, success=True)


class Mutation(graphene.ObjectType):
    create_review = CreateReview.Field()
    create_product = CreateProduct.Field()
    update_product = UpdateProduct.Field()


schema = graphene.Schema(query=Query, mutation=Mutation)

